SELECT [qSoloVend-PerGriglieAgenti].[Credit Manager], [qSoloVend-PerGriglieAgenti].GeoZone2Description, [qSoloVend-PerGriglieAgenti].GeoZone1Description, [qSoloVend-PerGriglieAgenti].[Salesperson Code], [qSoloVend-PerGriglieAgenti].Salesperson, [qSoloVend-PerGriglieAgenti].[Sell-to Customer No_], [qSoloVend-PerGriglieAgenti].[Sell-to Name], [qSoloVend-PerGriglieAgenti].[Purchase Group], [qSoloVend-PerGriglieAgenti].[Payment Method Code], [qSoloVend-PerGriglieAgenti].[Payment Terms Code], [qSoloVend-PerGriglieAgenti].[Current Risk], [qSoloVend-PerGriglieAgenti].[risk rating], [qSoloVend-PerGriglieAgenti].[trademark code], [qSoloVend-PerGriglieAgenti].[Sales Line].[requested delivery date] AS [Req Delivery Date], Sum([qSoloVend-PerGriglieAgenti].PairsSold) AS PairsSold, Sum([qSoloVend-PerGriglieAgenti].ValueSold) AS ValueSold, Sum([qSoloVend-PerGriglieAgenti].ValueSoldVAT) AS ValueSoldVAT, Sum([qSoloVend-PerGriglieAgenti].PairsReadyForShipping) AS SommaDiPairsReadyForShipping, Sum([qSoloVend-PerGriglieAgenti].ValueReadyForShipping) AS SommaDiValueReadyForShipping, IIf([Securities Received]=1,"Y","N") AS [Securities Received_], IIf([Blocked for Assignments]=1,"Y","N") AS [Blocked for Assignments_], [qSoloVend-PerGriglieAgenti].[Reason Block Code], "" AS [NOTE]
FROM [qSoloVend-PerGriglieAgenti]
WHERE ((([qSoloVend-PerGriglieAgenti].OrderType)="Progr" Or ([qSoloVend-PerGriglieAgenti].OrderType)="Pronto"))
GROUP BY [qSoloVend-PerGriglieAgenti].[Credit Manager], [qSoloVend-PerGriglieAgenti].GeoZone2Description, [qSoloVend-PerGriglieAgenti].GeoZone1Description, [qSoloVend-PerGriglieAgenti].[Salesperson Code], [qSoloVend-PerGriglieAgenti].Salesperson, [qSoloVend-PerGriglieAgenti].[Sell-to Customer No_], [qSoloVend-PerGriglieAgenti].[Sell-to Name], [qSoloVend-PerGriglieAgenti].[Purchase Group], [qSoloVend-PerGriglieAgenti].[Payment Method Code], [qSoloVend-PerGriglieAgenti].[Payment Terms Code], [qSoloVend-PerGriglieAgenti].[Current Risk], [qSoloVend-PerGriglieAgenti].[risk rating], [qSoloVend-PerGriglieAgenti].[trademark code], [qSoloVend-PerGriglieAgenti].[Sales Line].[requested delivery date], IIf([Securities Received]=1,"Y","N"), IIf([Blocked for Assignments]=1,"Y","N"), [qSoloVend-PerGriglieAgenti].[Reason Block Code], "", [qSoloVend-PerGriglieAgenti].[season code]
HAVING ((([qSoloVend-PerGriglieAgenti].[Payment Method Code])="RDA") AND ((IIf([Securities Received]=1,"Y","N"))="N") AND (([qSoloVend-PerGriglieAgenti].[season code])=[forms]![principale]![creditofiltrostagione2])) OR (((IIf([Blocked for Assignments]=1,"Y","N"))="Y") AND (([qSoloVend-PerGriglieAgenti].[season code])=[forms]![principale]![creditofiltrostagione2]))
ORDER BY [qSoloVend-PerGriglieAgenti].GeoZone2Description, [qSoloVend-PerGriglieAgenti].GeoZone1Description, [qSoloVend-PerGriglieAgenti].[Sell-to Name], [qSoloVend-PerGriglieAgenti].[trademark code];

